// Build Attachments - VTC Elite Reporting
// SOLO 2 adjuntos: MP3 (audio ElevenLabs) + PDF (reporte pixel-perfect Vercel,
// con la TRANSCRIPCION COMPLETA incluida dentro del propio PDF). El adjunto TXT
// fue eliminado a proposito: la transcripcion ya no viaja como archivo aparte.
// "Send an Email" adjunta por nombre de propiedad binaria via attach_list.
const P = $('Preparar Datos').first().json;
const empId = String(P.empleado_id || '0000').replace(/[^A-Za-z0-9_-]+/g, '_');
const fecha = String(P.fecha_formato || 'sesion').replace(/[^A-Za-z0-9_-]+/g, '_');
// Nombre dinámico {nombre-slug}_{YYYYMMDD}_{HHMM} (hora de Cancún) calculado en
// "Preparar Datos"; si faltara (workflow viejo), se reconstruye como red de seguridad.
const fileBase = String(P.file_base || (empId + '_' + fecha)).replace(/[^A-Za-z0-9_-]+/g, '_');
const binary = {}; const present = []; const notes = [];

function bytesOf(fs) { if (!fs) return 0; const m = String(fs).match(/([\d.]+)\s*(GB|MB|kB|KB|B)/i); if (!m) return 0; const v = parseFloat(m[1]); const u = m[2].toUpperCase(); return u === 'GB' ? v * 1e9 : (u === 'MB' ? v * 1e6 : (u === 'KB' ? v * 1e3 : v)); }

// 1) MP3 - solo si <= 24 MB (evita rebote SMTP; entrega el PDF igualmente)
try {
  const ab = $('Fetch Audio HTTP').first().binary;
  if (ab && ab.data) {
    const sz = bytesOf(ab.data.fileSize);
    if (sz > 0 && sz > 24 * 1e6) { notes.push('audio_omitido_por_tamano:' + ab.data.fileSize); }
    else { binary.data = Object.assign({}, ab.data, { fileName: `${fileBase}.mp3` }); present.push('data'); }
  } else { notes.push('audio_no_disponible'); }
} catch (e) { notes.push('audio_err:' + String(e.message).slice(0, 80)); }

// 2) PDF - reporte visual con transcripcion completa embebida
try {
  const pb = $('Fetch PDF').first().binary;
  if (pb && pb.pdf) { binary.pdf = Object.assign({}, pb.pdf, { fileName: `${fileBase}.pdf` }); present.push('pdf'); }
  else { notes.push('pdf_no_disponible'); }
} catch (e) { notes.push('pdf_err:' + String(e.message).slice(0, 80)); }

return [{ json: { success: true, has_attachment: present.length > 0, attach_list: present.join(','), files: { audio: binary.data ? binary.data.fileName : null, pdf: binary.pdf ? binary.pdf.fileName : null }, notes }, binary: binary }];

